// https://docs.rs/diesel_migrations/latest/diesel_migrations/macro.embed_migrations.html
// Due to limitations in rusts proc-macro API there is currently no way to signal that a
// specific proc macro should be rerun if some external file changes/is added. This implies
// that embed_migrations! cannot regenerate the list of embedded migrations if only the
// migrations are changed. This limitation can be solved by adding a custom build.rs file
// to your crate, such that the crate is rebuild if the migration directory changes.
fn main() -> Result<(), Box<dyn std::error::Error>> {
    println!("cargo:rerun-if-changed=migrations");
    println!("cargo:rerun-if-changed=src/generated/schema.rs");

    if let Err(e) = parse_schema_rs() {
        eprintln!("parse_schema_rs error: {e}");
        return Err(e);
    }

    Ok(())
}

fn parse_schema_rs() -> Result<(), Box<dyn std::error::Error>> {
    use std::fmt::Write as _;
    use std::fs;
    use std::path::Path;

    let manifest_dir = std::env::var("CARGO_MANIFEST_DIR")?;
    let schema_path = Path::new(&manifest_dir).join("src/generated/schema.rs");
    let schema_content = fs::read_to_string(&schema_path)?;

    let mut entries: Vec<(String, String, String)> = Vec::new();
    let mut lines: Vec<&str> = schema_content.lines().collect();
    lines.push("");

    let mut i = 0;
    let mut table_name = String::new();
    while i < lines.len() {
        let line = lines[i].trim();

        if line.starts_with("diesel::table!") {
            table_name.clear();
            i += 1;
            while i < lines.len() {
                let inner_line = lines[i].trim();
                if inner_line.contains("(id)") {
                    let part = inner_line.split('(').next().unwrap_or("");
                    table_name = part.trim().to_string();
                    break;
                }
                i += 1;
            }
        }

        if !table_name.is_empty() && line.contains("->") {
            let parts: Vec<&str> = line.split("->").collect();
            if parts.len() == 2 {
                let col_name = parts[0].trim();
                let type_part = parts[1].trim().trim_end_matches(',');
                let sql_type = map_sql_type(type_part);
                let tn = table_name.clone();
                entries.push((tn, col_name.to_string(), sql_type.to_string()));
            }
        }

        if line == "}" && !table_name.is_empty() {
            table_name.clear();
        }

        i += 1;
    }

    entries.sort_by(|a, b| {
        let t = a.0.cmp(&b.0);
        if t == std::cmp::Ordering::Equal {
            a.1.cmp(&b.1)
        } else {
            t
        }
    });

    let src_dir = Path::new(&manifest_dir).join("src");
    let dest_path = src_dir.join("generated/columns.rs");
    let header = concat!(
        "//! Auto-generated column constants from the Diesel schema. Do not edit.\n",
        "\n",
        "#![allow(missing_docs)]\n",
        "\n",
        "#[doc(hidden)]\n",
        "pub const SCHEMA_ENTRIES: &[(&str, &str, &str)] = &[\n",
    );
    let mut output = String::from(header);
    for entry in &entries {
        let escaped_table = entry.0.replace('"', "\\\"");
        let escaped_col = entry.1.replace('"', "\\\"");
        let escaped_type = entry.2.replace('"', "\\\"");
        let _ = writeln!(
            output,
            "    (\"{escaped_table}\", \"{escaped_col}\", \"{escaped_type}\"),"
        );
    }
    output.push_str("];\n");

    fs::write(dest_path, output)?;

    Ok(())
}

fn map_sql_type(diesel_type: &str) -> &'static str {
    let inner = diesel_type
        .strip_prefix("Nullable<")
        .and_then(|s| s.strip_suffix('>'))
        .unwrap_or(diesel_type);
    match inner {
        "Integer" | "Bool" => "INTEGER",
        "Timestamp" => "TIMESTAMP",
        "Binary" => "BLOB",
        "Text" => "TEXT",
        "Double" => "DOUBLE",
        _ => "TEXT",
    }
}

#![allow(missing_docs)] // covers AppBehaviourEvent generated by NetworkBehaviour derive

//! P2P network behavior and protocol definitions

use crate::network::NetworkSize;
use crate::p2plog_debug;
use libp2p::gossipsub;
use libp2p::request_response;
use libp2p::swarm::NetworkBehaviour;
use serde::{Deserialize, Serialize};

/// Chat protocol name for direct messages
pub const DM_PROTOCOL_NAME: &str = "/p2p-chat/dm/1.0.0";

/// Default chat topic
pub const CHAT_TOPIC: &str = "test-net";

/// Direct message content with timestamp and sender info
#[derive(Debug, Clone, Serialize, Deserialize, Default)]
#[serde(default)]
pub struct DirectMessage {
    /// The message content/text
    pub content: String,
    /// Unix timestamp when the message was created
    pub timestamp: i64,
    /// Optional timestamp of when the message was sent to the network
    pub sent_at: Option<f64>,
    /// Optional nickname of the sender
    pub nickname: Option<String>,
    /// Optional unique identifier for this message
    pub msg_id: Option<String>,
    /// Optional ID of the message this is acknowledging/replying to
    pub ack_for: Option<String>,
    /// Optional timestamp of when this message was received
    pub received_at: Option<f64>,
}

/// Broadcast message content with timestamp and sender info
#[derive(Debug, Clone, Serialize, Deserialize, Default)]
#[serde(default)]
pub struct BroadcastMessage {
    /// The message content/text
    pub content: String,
    /// Optional timestamp of when the message was sent
    pub sent_at: Option<f64>,
    /// Optional nickname of the sender
    pub nickname: Option<String>,
    /// Optional unique identifier for this message
    pub msg_id: Option<String>,
}

/// JSON codec for direct message protocol
pub type ChatCodec = libp2p_request_response::json::codec::Codec<DirectMessage, DirectMessage>;

/// Combined network behavior for p2p chat
#[derive(NetworkBehaviour)]
pub struct AppBehaviour {
    /// Gossipsub protocol handler for broadcast messages
    pub gossipsub: gossipsub::Behaviour,
    /// Request-response protocol handler for direct messages
    pub request_response: request_response::Behaviour<ChatCodec>,
    /// mDNS protocol handler for peer discovery (when mdns feature is enabled)
    #[cfg(feature = "mdns")]
    pub mdns: libp2p::mdns::tokio::Behaviour,
}

// AppBehaviourEvent is auto-generated by the NetworkBehaviour derive macro

/// Build the app behavior with appropriate protocols and configurations
///
/// # Arguments
/// * `key` - libp2p identity keypair
/// * `network_size` - Network size enum for tuning behavior parameters
#[must_use]
pub fn build_behaviour(key: &libp2p_identity::Keypair, network_size: NetworkSize) -> AppBehaviour {
    p2plog_debug(format!(
        "Building behavior for network size: {network_size:?}"
    ));
    // Configure Gossipsub based on network size
    let gossipsub_config = match network_size {
        NetworkSize::Small => {
            // 0-3 peers: aggressive message propagation
            gossipsub::ConfigBuilder::default()
                .max_transmit_size(262_144)
                .history_gossip(3)
                .history_length(20)
                .heartbeat_interval(std::time::Duration::from_secs(1))
                .build()
                .expect("valid gossipsub config")
        }
        NetworkSize::Medium => {
            // 4-15 peers: balanced settings
            gossipsub::ConfigBuilder::default()
                .max_transmit_size(262_144)
                .history_gossip(6)
                .history_length(30)
                .heartbeat_interval(std::time::Duration::from_secs(2))
                .build()
                .expect("valid gossipsub config")
        }
        NetworkSize::Large => {
            // 16+ peers: conservative settings
            gossipsub::ConfigBuilder::default()
                .max_transmit_size(262_144)
                .history_gossip(12)
                .history_length(50)
                .heartbeat_interval(std::time::Duration::from_secs(5))
                .build()
                .expect("valid gossipsub config")
        }
    };

    let gossipsub = gossipsub::Behaviour::new(
        gossipsub::MessageAuthenticity::Signed(key.clone()),
        gossipsub_config,
    )
    .unwrap_or_else(|e| {
        panic!("Failed to create gossipsub behavior: {e}");
    });

    let request_response = request_response::Behaviour::new(
        [(
            libp2p::StreamProtocol::new(DM_PROTOCOL_NAME),
            request_response::ProtocolSupport::Full,
        )],
        Default::default(),
    );

    #[cfg(feature = "mdns")]
    let mdns = libp2p::mdns::tokio::Behaviour::new(
        libp2p::mdns::Config::default(),
        libp2p::PeerId::from_public_key(&key.public()),
    )
    .expect("valid mdns");

    AppBehaviour {
        gossipsub,
        request_response,
        #[cfg(feature = "mdns")]
        mdns,
    }
}

/// Build a fully configured libp2p swarm for chat.
///
/// Sets up TCP (with nodelay), optional QUIC transport, the app behaviour
/// with adaptive network size, and a 60-second idle connection timeout.
pub fn build_swarm(
    network_size: NetworkSize,
) -> color_eyre::Result<libp2p::swarm::Swarm<AppBehaviour>> {
    use std::time::Duration;

    let key = crate::get_libp2p_identity()?;

    let base = libp2p::SwarmBuilder::with_existing_identity(key)
        .with_tokio()
        .with_tcp(
            libp2p::tcp::Config::default().nodelay(true),
            libp2p::noise::Config::new,
            libp2p::yamux::Config::default,
        )?;

    #[cfg(feature = "quic")]
    let swarm = base
        .with_quic()
        .with_behaviour(|key| Ok(build_behaviour(key, network_size)))?
        .with_swarm_config(|c| c.with_idle_connection_timeout(Duration::from_secs(60)))
        .build();

    #[cfg(not(feature = "quic"))]
    let swarm = base
        .with_behaviour(|key| Ok(build_behaviour(key, network_size)))?
        .with_swarm_config(|c| c.with_idle_connection_timeout(Duration::from_secs(60)))
        .build();

    Ok(swarm)
}

