//! Headless CLI binary — minimal footprint, reads from stdin, writes to stderr.

use libp2p::{futures::StreamExt, gossipsub};
use p2p_app::current_timestamp;
use p2p_app::logging::p2plog_info;
use p2p_app::{BroadcastMessage, build_swarm, get_network_size};
use tokio::io::{AsyncBufReadExt as _, BufReader};

enum Event {
    Swarm(Box<libp2p::swarm::SwarmEvent<p2p_app::behavior::AppBehaviourEvent>>),
    Stdin(Option<String>),
}

fn extract_tcp_port(address: &libp2p::Multiaddr) -> Option<i32> {
    address.iter().find_map(|p| match p {
        libp2p::multiaddr::Protocol::Tcp(port) => Some(i32::from(port)),
        _ => None,
    })
}

#[cfg(feature = "quic")]
fn extract_udp_port(address: &libp2p::Multiaddr) -> Option<i32> {
    address.iter().find_map(|p| match p {
        libp2p::multiaddr::Protocol::Udp(port) => Some(i32::from(port)),
        _ => None,
    })
}

fn handle_listen_addr_event(address: &libp2p::Multiaddr) {
    p2p_app::logging::p2plog_info(format!("Listening on: {address}"));
    if let Some(port) = extract_tcp_port(address) {
        let _ = p2p_app::save_listen_ports(Some(port), None);
    }
    #[cfg(feature = "quic")]
    if let Some(port) = extract_udp_port(address) {
        let (tcp, _) = p2p_app::load_listen_ports().unwrap_or((None, None));
        let _ = p2p_app::save_listen_ports(tcp, Some(port));
    }
}

fn handle_message_event(propagation_source: &libp2p::PeerId, message: &gossipsub::Message) {
    let sender = propagation_source.to_string();
    let sender_short = &sender[..8.min(sender.len())];
    let msg_str = String::from_utf8_lossy(&message.data);
    if let Ok(bcast) = serde_json::from_str::<BroadcastMessage>(&msg_str) {
        p2p_app::logging::p2plog_info(format!("[{}] {}", sender_short, bcast.content));
    } else {
        p2p_app::logging::p2plog_info(format!("[{sender_short}] {msg_str}"));
    }
}

#[tokio::main]
async fn main() -> color_eyre::Result<()> {
    color_eyre::install()?;
    p2p_app::logging::init_logging();
    p2plog_info("Starting P2P Chat CLI".to_string());

    // Initialize database once at startup (logs database path and peer ID)
    let _db = p2p_app::init_database()?;

    let network_size = match get_network_size() {
        Ok(size) => {
            p2plog_info(format!("Network size detected: {size:?}"));
            size
        }
        Err(e) => {
            p2plog_info(format!(
                "Could not determine network size, defaulting to Small: {e}"
            ));
            p2p_app::NetworkSize::Small
        }
    };

    let mut swarm = build_swarm(network_size)?;

    let listen_addr: libp2p::Multiaddr = "/ip4/0.0.0.0/tcp/0".parse()?;
    swarm.listen_on(listen_addr)?;

    let topic = gossipsub::IdentTopic::new(p2p_app::CHAT_TOPIC);
    swarm.behaviour_mut().gossipsub.subscribe(&topic)?;

    let stdin = BufReader::new(tokio::io::stdin());
    let mut lines = stdin.lines();

    loop {
        let event = tokio::select! {
            swarm_event = swarm.select_next_some() => Some(Event::Swarm(Box::new(swarm_event))),
            line = lines.next_line() => Some(Event::Stdin(line.ok().flatten())),
        };

        match event {
            Some(Event::Swarm(event)) => match *event {
                libp2p::swarm::SwarmEvent::NewListenAddr { address, .. } => {
                    handle_listen_addr_event(&address);
                }
                libp2p::swarm::SwarmEvent::ConnectionEstablished { peer_id, .. } => {
                    p2p_app::logging::p2plog_info(format!("Connected to: {peer_id} (peers: 1)"));
                }
                libp2p::swarm::SwarmEvent::ConnectionClosed { peer_id, .. } => {
                    p2p_app::logging::p2plog_info(format!("Disconnected from: {peer_id}"));
                }
                libp2p::swarm::SwarmEvent::Behaviour(
                    p2p_app::behavior::AppBehaviourEvent::Gossipsub(
                        libp2p::gossipsub::Event::Message {
                            propagation_source,
                            message,
                            ..
                        },
                    ),
                ) => {
                    handle_message_event(&propagation_source, &message);
                }
                _ => {}
            },
            Some(Event::Stdin(Some(text))) if !text.is_empty() => {
                let msg = BroadcastMessage {
                    content: text,
                    sent_at: Some(current_timestamp()),
                    nickname: None,
                    msg_id: None,
                };
                if let Ok(json) = serde_json::to_string(&msg) {
                    let _ = swarm
                        .behaviour_mut()
                        .gossipsub
                        .publish(topic.clone(), json.as_bytes());
                }
            }
            Some(Event::Stdin(_)) => {}
            None => break,
        }
    }
    Ok(())
}

//! Dioxus desktop binary for the P2P chat application.

#[cfg(feature = "dioxus-desktop")]
mod dioxus {
    use dioxus_desktop::tao;
    use dioxus_desktop::{Config, WindowBuilder};
    use libp2p::gossipsub;
    use std::collections::{HashMap, VecDeque};

    type Messages = VecDeque<p2p_app::DisplayMessage>;
    type MessageIds = VecDeque<Option<String>>;

    fn format_messages(
        topic_str: &str,
        max_messages: usize,
        local_nicknames: &HashMap<String, String>,
        received_nicknames: &HashMap<String, String>,
        own_nickname: &str,
    ) -> (Messages, MessageIds) {
        let mut messages = VecDeque::new();
        let mut message_ids = VecDeque::new();
        if let Ok(db_messages) = p2p_app::load_messages(topic_str, max_messages) {
            for msg in db_messages.iter().rev() {
                let ts = p2p_app::format_peer_datetime(msg.created_at);
                let sender = if msg.peer_id.is_none() {
                    msg.sender_nickname
                        .as_ref()
                        .map(|n| format!("[{}]", n))
                        .unwrap_or_else(|| format!("[{}]", own_nickname))
                } else {
                    msg.sender_nickname
                        .as_ref()
                        .map(|n| format!("[{}]", n))
                        .unwrap_or_else(|| {
                            let p = msg.peer_id.as_deref().unwrap_or("unknown");
                            let display =
                                p2p_app::peer_display_name(p, local_nicknames, received_nicknames);
                            format!("[{}]", display)
                        })
                };
                messages.push_back(p2p_app::DisplayMessage {
                    text: format!("{} {} {}", ts, sender, msg.content),
                    sender_peer_id: msg.peer_id.clone(),
                });
                message_ids.push_back(msg.msg_id.clone());
            }
        }
        (messages, message_ids)
    }

    pub fn main() {
        let rt = tokio::runtime::Builder::new_multi_thread()
            .enable_all()
            .build()
            .expect("Failed to create tokio runtime");

        rt.block_on(async {
            p2p_app::logging::init_logging();
            p2p_app::logging::set_tui_callback(|msg| eprintln!("{}", msg));
            let _db = p2p_app::init_database().expect("Failed to init database");

            let network_size = match p2p_app::get_network_size() {
                Ok(size) => {
                    p2p_app::p2plog_info(format!("Network size: {:?}", size));
                    size
                }
                Err(e) => {
                    p2p_app::p2plog_info(format!("Defaulting to Small: {}", e));
                    p2p_app::NetworkSize::Small
                }
            };

            let mut swarm = p2p_app::build_swarm(network_size).expect("Failed to build swarm");

            let _ = swarm.listen_on("/ip4/0.0.0.0/tcp/0".parse().unwrap());
            let _ = swarm
                .behaviour_mut()
                .gossipsub
                .subscribe(&gossipsub::IdentTopic::new(p2p_app::CHAT_TOPIC));

            let (swarm_handler, swarm_event_rx, swarm_cmd_tx) =
                p2p_app::spawn_swarm_handler(swarm, p2p_app::CHAT_TOPIC.to_string());

            p2p_app::dioxus_app::SWARM_CMD_TX
                .set(std::sync::Mutex::new(swarm_cmd_tx))
                .ok();

            let own_nickname =
                p2p_app::ensure_self_nickname().unwrap_or_else(|_| "Anonymous".to_string());

            let (local_nicknames, received_nicknames) = if let Ok(db_peers) = p2p_app::load_peers()
            {
                let mut local = HashMap::new();
                let mut received = HashMap::new();
                for p in db_peers {
                    if let Some(n) = p.peer_local_nickname {
                        local.insert(p.peer_id.clone(), n);
                    }
                    if let Some(n) = p.received_nickname {
                        received.insert(p.peer_id.clone(), n);
                    }
                }
                (local, received)
            } else {
                (HashMap::new(), HashMap::new())
            };

            let (initial_messages, initial_message_ids) = format_messages(
                p2p_app::CHAT_TOPIC,
                1000,
                &local_nicknames,
                &received_nicknames,
                &own_nickname,
            );

            let mut initial_peers = if let Ok(db_peers) = p2p_app::load_known_peers() {
                let mut peers = VecDeque::new();
                let mut seen = std::collections::HashSet::new();
                for p in &db_peers {
                    if !seen.insert(p.peer_id.clone()) {
                        continue;
                    }
                    peers.push_back(p2p_app::PeerRecord {
                        peer_id: p.peer_id.clone(),
                        first_seen: p2p_app::format_peer_datetime(p.first_seen),
                        last_seen: p2p_app::format_peer_datetime(p.last_seen),
                    });
                }
                peers
            } else {
                VecDeque::new()
            };

            let mut pv: Vec<_> = initial_peers.drain(..).collect();
            pv.sort_by(|a, b| b.last_seen.cmp(&a.last_seen));
            initial_peers = pv.into();

            let mut broadcast_receipts: HashMap<String, HashMap<String, f64>> = HashMap::new();
            let mut dm_receipts: HashMap<String, (String, f64)> = HashMap::new();
            if let Ok(receipts) = p2p_app::load_receipts() {
                for r in receipts {
                    if r.kind == 0 {
                        broadcast_receipts
                            .entry(r.msg_id.clone())
                            .or_default()
                            .insert(r.peer_id.clone(), r.confirmed_at);
                    } else {
                        dm_receipts.insert(r.msg_id.clone(), (r.peer_id.clone(), r.confirmed_at));
                    }
                }
            }

            let local_peer_id = p2p_app::get_local_peer_id()
                .map(|id| id.to_string())
                .unwrap_or_else(|_| "unknown".to_string());

            let init_data = p2p_app::dioxus_app::InitData {
                own_nickname,
                local_peer_id,
                topic_str: p2p_app::CHAT_TOPIC.to_string(),
                local_nicknames,
                received_nicknames,
                messages: initial_messages,
                message_ids: initial_message_ids,
                peers: initial_peers,
                broadcast_receipts,
                dm_receipts,
            };
            p2p_app::dioxus_app::INIT_DATA
                .set(std::sync::Mutex::new(Some(init_data)))
                .ok();

            tokio::spawn(async move {
                let _ = swarm_handler.await;
            });

            tokio::spawn(async move {
                let mut rx = swarm_event_rx;
                while let Some(event) = rx.recv().await {
                    if let Some(tx) = p2p_app::dioxus_app::SWARM_EVENT_TX.get() {
                        let _ = tx.unbounded_send(event);
                    }
                }
            });
        });

        let _guard = rt.enter();

        let config = Config::new()
            .with_window(
                WindowBuilder::new()
                    .with_title("P2P Chat Desktop")
                    .with_inner_size(tao::dpi::LogicalSize::new(900.0, 700.0)),
            )
            .with_custom_head(
                r#"<style>html,body{margin:0;padding:0;height:100%;overflow:hidden;}</style>"#
                    .to_string(),
            );

        dioxus_desktop::launch::launch(
            p2p_app::dioxus_app::App as fn() -> dioxus::prelude::Element,
            vec![],
            vec![Box::new(config)],
        );
    }
}

#[cfg(not(feature = "dioxus-desktop"))]
fn main() {
    eprintln!("This binary requires the 'dioxus-desktop' feature.");
    eprintln!("Run with: cargo run --bin p2p_chat_dioxus --features dioxus-desktop");
}

#[cfg(feature = "dioxus-desktop")]
fn main() {
    dioxus::main();
}

//! TUI binary — ratatui-based terminal interface and headless fallback entry point.

use libp2p::gossipsub;
use p2p_app::build_swarm;
use p2p_app::logging::{init_logging, p2plog_info};

#[cfg(feature = "tui")]
mod tui {
    //! Four-task TUI architecture for `p2p_app`
    //!
    //! ## Overview
    //!
    //! This module implements a concurrent, event-driven terminal UI using async Rust.
    //! Four independent tasks communicate via MPSC channels, each responsible for a specific concern:
    //!
    //! 1. **`SwarmHandler`** - Listens to libp2p network events and translates them to app-level `SwarmEvent`
    //! 2. **`InputHandler`** - Polls terminal for keyboard/mouse input and sends `InputEvent`
    //! 3. **`CommandProcessor`** - Receives `InputEvent` and `SwarmEvent`, mutates `AppState`, sends `SwarmCommand`
    //! 4. **`RenderLoop`** - Reads `AppState` and renders the TUI on demand
    //!
    //! ## Architecture
    //!
    //! ```text
    //! ┌─────────────────────────────────────────────────────┐
    //! │                  libp2p Swarm                       │
    //! └────────────────────────┬────────────────────────────┘
    //!                          │
    //!                          ↓
    //!                  SwarmHandler Task
    //!                    (libp2p events)
    //!                          │
    //!                          ↓ SwarmEvent (mpsc)
    //!          ┌───────────────────────────────┐
    //!          │    CommandProcessor Task      │
    //!          │  ┌─────────────────────────┐  │
    //!          │  │  Shared AppState        │  │
    //!          │  │ (Arc<Mutex<AppState>>)  │  │
    //!          │  └─────────────────────────┘  │
    //!          └───────────────────────────────┘
    //!                 ↑              ↑
    //!    InputEvent   │              │ SwarmEvent
    //!      (mpsc)     │              │ (mpsc)
    //!                 │              │
    //!          InputHandler Task  SwarmHandler Task
    //!                 ↑
    //!          Terminal Input
    //!
    //! RenderLoop continuously reads AppState and redraws terminal.
    //! ```
    //!
    //! ## State Management
    //!
    //! All TUI state is centralized in `AppState` behind an `Arc<Mutex<>>` for safe concurrent access.
    //! Only `CommandProcessor` mutates state; other tasks read-only or signal mutations through channels.
    //!
    //! Channel Capacity: 100 events max in flight per channel (prevents unbounded buffering).
    //!
    //! ## Key Design Decisions
    //!
    //! - **`Arc<Mutex>` over `RwLock`**: Simplicity. Most operations read and modify multiple fields atomically.
    //! - **Polling input instead of event subscriptions**: Works on all platforms with crossterm.
    //! - **Event-driven redraws**: UI updates only when input or network state changes.
    //! - **Immutable channel types**: Each task has dedicated input/output channels, no shared mutable channels.

    pub use p2p_app::tui_tabs::DynamicTabs;
    use ratatui_textarea::TextArea;

    pub mod click_handlers;
    mod command_processor;
    pub mod event_source;
    pub mod input_processor;
    pub mod main_loop;
    pub mod message_handlers;
    pub mod render_loop;
    pub mod scroll_handlers;
    pub mod state;
    #[cfg(test)]
    #[path = "../../../tests/unit/unit_bin_tui_test_helpers.rs"]
    pub mod test_helpers;
}

#[tokio::main]
async fn main() -> color_eyre::Result<()> {
    color_eyre::install()?;
    init_logging();
    p2p_app::logging::set_tui_callback(|_| p2p_app::logging::request_tui_redraw());

    // Initialize database once at startup (logs database path and peer ID)
    let _db = p2p_app::init_database()?;

    let topic = gossipsub::IdentTopic::new(p2p_app::CHAT_TOPIC);

    let network_size = match p2p_app::get_network_size() {
        Ok(size) => {
            p2plog_info(format!("Network size detected: {size:?}"));
            size
        }
        Err(e) => {
            p2plog_info(format!(
                "Could not determine network size, defaulting to Small: {e}"
            ));
            p2p_app::NetworkSize::Small
        }
    };

    let mut swarm = build_swarm(network_size)?;

    let listen_addr: libp2p::Multiaddr = "/ip4/0.0.0.0/tcp/0".parse()?;
    swarm.listen_on(listen_addr)?;

    swarm.behaviour_mut().gossipsub.subscribe(&topic)?;

    // Use new 4-task architecture instead of monolithic tokio::select!
    tui::main_loop::run_new_tui(swarm, p2p_app::CHAT_TOPIC.to_string()).await
}

